// 2xx: body is in $json.data (responseFormat:text)
// 4xx with continueOnFail: body is embedded in $json.error.message as '400 - {json}'
let body = $json.data || '';
const httpError = $json.error;
if (!body && httpError && httpError.message) {
  const dashIdx = httpError.message.indexOf(' - ');
  body = dashIdx !== -1 ? httpError.message.substring(dashIdx + 3) : httpError.message;
}
const statusCode = (httpError && httpError.status) || 200;

let parsed = {};
try { parsed = JSON.parse(body); } catch(e) { parsed = {}; }

const detail = parsed.detail || parsed.error || null;
const lowerBody = body.toLowerCase();

if (detail) {
  const msg = typeof detail === 'string' ? detail : JSON.stringify(detail);
  if (msg.toLowerCase().includes('already exist')) {
    return [{json: {status: 'already_registered', message: 'This email is already registered. Head to the Link Records tab to upload and link your data.'}}];
  }
  return [{json: {status: 'error', detail: msg}}];
}
if (lowerBody.includes('already exist')) {
  return [{json: {status: 'already_registered', message: 'This email is already registered. Head to the Link Records tab to upload and link your data.'}}];
}
if (statusCode >= 400 || lowerBody.includes('error') || lowerBody.includes('invalid')) {
  return [{json: {status: 'error', detail: body || 'Registration failed.'}}];
}
return [{json: {status: 'code_sent', message: 'Registration started. Check your email for a verification code.'}}];
